// Compara usuário e senha vindos do app com as linhas da planilha.
// Comparação simples, sem hash — combinado com o Diego que é só identificação, não segurança forte.
const body = $('Webhook Login').first().json.body || {};
const usuarioDigitado = (body.usuario || '').toString().trim().toLowerCase();
const senhaDigitada = (body.senha || '').toString();

const linhas = $input.all().map(i => i.json);
const achou = linhas.find(row =>
  (row.usuario || '').toString().trim().toLowerCase() === usuarioDigitado &&
  (row.senha || '').toString() === senhaDigitada &&
  usuarioDigitado !== ''
);

if (achou) {
  return [{ json: { ok: true, nome: achou.nome || achou.usuario } }];
}
return [{ json: { ok: false } }];
